import {NgModule} from '@angular/core';
import {CommonModule} from '@angular/common';
import {RouterModule} from '@angular/router';
import {MerchandiseRoutes} from './merchandise.routing';
import {NgxDatatableModule} from '@swimlane/ngx-datatable';
import {FormsModule, ReactiveFormsModule} from '@angular/forms';
import { MatDialogModule } from '@angular/material';
import {MatButtonModule} from '@angular/material/button';
import {MatProgressSpinnerModule} from '@angular/material/progress-spinner';
import {MatTableModule} from '@angular/material/table';
import {MatPaginatorModule} from '@angular/material/paginator';
import {NgxPrintModule} from "ngx-print";
import {NgxBarcodeModule} from "ngx-barcode";
import {PrintService} from "app/services/print.service";
//service
import {WarehouseExpService} from 'app/services/warehouse-exp.service';
import {MerchandiseServices} from 'app/services/merchandise.services';
import { SystemService } from 'app/services/system.services';
//component
import { MerchandiseDeliveryComponent } from './delivery/merchandise-delivery.component';
import { PrintBillComponent } from './delivery/print-bill/print-bill.component';
//primeng service
import { ConfirmationService } from 'primeng/api';
import { MessageService } from 'primeng/api';
//primeng
import { CalendarModule } from 'primeng/calendar';
import { DropdownModule } from 'primeng/dropdown';
import { TableModule } from 'primeng/table';
import { CheckboxModule } from 'primeng/checkbox';
import { ConfirmDialogModule } from 'primeng/confirmdialog';
import { ToastModule } from 'primeng/toast';
import { ProgressSpinnerModule } from 'primeng/progressspinner';

@NgModule({
    imports: [
        CommonModule,
        FormsModule,
        ReactiveFormsModule,
        RouterModule.forChild(MerchandiseRoutes),
        NgxDatatableModule,
        MatDialogModule,
        MatButtonModule,
        MatProgressSpinnerModule,
        MatTableModule,
        MatPaginatorModule,
        NgxPrintModule,
        NgxBarcodeModule,
        CalendarModule,
        DropdownModule,
        TableModule,
        CheckboxModule,
        ConfirmDialogModule,
        ToastModule,
        ProgressSpinnerModule
    ],
    declarations: [
        MerchandiseDeliveryComponent,
        PrintBillComponent,
    ],
    providers: [
        MerchandiseServices,
        WarehouseExpService,
        PrintService,
        ConfirmationService,
        SystemService,
        MessageService
    ],
    entryComponents: [
        PrintBillComponent
    ]
})
export class MerchandiseModule {
}
